:root {
  font-family: 'Inter', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  color: #0f172a;
  background: #f8fafc;
}

body {
  margin: 0;
  background: #f8fafc;
}

.app-shell {
  max-width: 1200px;
  margin: 0 auto;
  padding: 2rem 1.25rem 4rem;
}

.hero {
  background: linear-gradient(135deg, #0f172a, #1d4ed8);
  color: #fff;
  border-radius: 32px;
  padding: 2.5rem;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 2rem;
  align-items: center;
}

.hero h1 {
  font-size: clamp(2.25rem, 4vw, 3.5rem);
  margin-bottom: 0.5rem;
}

.hero-card {
  padding: 1.5rem;
  border: 1px solid rgba(255, 255, 255, 0.35);
  border-radius: 20px;
  background: rgba(255, 255, 255, 0.08);
}

.hero-card h3 {
  margin: 0;
}

.tag {
  display: inline-flex;
  padding: 0.2rem 0.8rem;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.2);
  font-size: 0.8rem;
  margin-bottom: 0.75rem;
}

.hero-actions button {
  margin-right: 0.75rem;
}

.section {
  margin-top: 3rem;
  padding: 2rem;
  background: #fff;
  border-radius: 28px;
  box-shadow: 0 10px 45px rgba(15, 23, 42, 0.08);
}

.section-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.eyebrow {
  text-transform: uppercase;
  letter-spacing: 0.2em;
  font-size: 0.75rem;
  color: #94a3b8;
  margin: 0;
}

.lead {
  color: #e2e8f0;
}

.menu-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1rem;
  margin-top: 1.5rem;
}

.menu-card {
  padding: 1.25rem;
  border-radius: 18px;
  background: #f8fafc;
  border: 1px solid #e2e8f0;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.menu-card__header {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
}

.menu-card__meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 0.85rem;
  color: #475569;
}

.section.split {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 1.5rem;
  padding: 2.5rem;
}

.result-card {
  border-radius: 16px;
  padding: 1rem;
  background: #ecfccb;
  border: 1px solid #bef264;
  color: #4b6f21;
}

.result-card.error {
  background: #fee2e2;
  border-color: #fecaca;
  color: #991b1b;
}

.result-card.ghost {
  background: #f1f5f9;
  border-color: #e2e8f0;
  color: #475569;
}

.order-tracking ul {
  list-style: none;
  padding: 0;
  margin: 0.75rem 0 0;
}

.order-tracking li {
  padding: 0.35rem 0;
  border-bottom: 1px solid #e2e8f0;
}

.order-tracking li.done {
  color: #16a34a;
  font-weight: 600;
}

.role-tabs button {
  margin-left: 0.75rem;
}

.dashboard-card {
  margin-top: 1.5rem;
  padding: 1.5rem;
  border-radius: 18px;
  border: 1px solid #e2e8f0;
  background: #f8fafc;
}

.dashboard-card dl {
  margin: 0;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 0.75rem;
}

.dashboard-card dt {
  text-transform: uppercase;
  font-size: 0.7rem;
  color: #94a3b8;
}

.dashboard-card dd {
  margin: 0 0 0.5rem;
  font-weight: 600;
}

button {
  cursor: pointer;
  border: none;
  padding: 0.75rem 1.5rem;
  border-radius: 999px;
  font-weight: 600;
  transition: transform 0.2s ease;
}

button.primary {
  background: #0f172a;
  color: #fff;
}

button.ghost {
  background: #e2e8f0;
  color: #0f172a;
}

button.base {
  border: 1px solid #cbd5f5;
  background: rgba(0, 0, 0, 0.03);
}

button:hover {
  transform: translateY(-1px);
}

@media (max-width: 600px) {
  .hero,
  .section,
  .section.split {
    padding: 1.5rem;
  }

  .hero-actions button {
    width: 100%;
    margin: 0 0 0.5rem;
  }
}

import { useEffect, useMemo, useState } from 'react';
import './App.css';

function App() {
  const [menu, setMenu] = useState([]);
  const [loadingMenu, setLoadingMenu] = useState(true);
  const [checkoutResult, setCheckoutResult] = useState(null);
  const [trackingResult, setTrackingResult] = useState(null);
  const [dashboardData, setDashboardData] = useState(null);
  const [lastRole, setLastRole] = useState('customer');

  useEffect(() => {
    const fetchMenu = async () => {
      try {
        const response = await fetch('/api/v1/menu');
        if (!response.ok) throw new Error('Menu unavailable');
        const data = await response.json();
        setMenu(data.dishes || []);
      } catch (error) {
        console.error(error);
      } finally {
        setLoadingMenu(false);
      }
    };

    fetchMenu();
  }, []);

  const featuredDish = useMemo(() => menu[0], [menu]);

  const handleCheckout = async () => {
    if (!menu.length) {
      setCheckoutResult({ error: 'Menu not loaded yet' });
      return;
    }

    const payload = {
      customer_name: 'Jordan Rivera',
      delivery_address: '512 Harbor Avenue, Suite 3',
      payment_method: 'Visa •••• 1184',
      cart: menu.slice(0, 2).map((dish) => ({ id: dish.id, quantity: 1 })),
    };

    try {
      const response = await fetch('/api/v1/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      const data = await response.json();
      setCheckoutResult(data.order ? { success: true, order: data.order } : { error: data.message });
    } catch (error) {
      console.error(error);
      setCheckoutResult({ error: 'Unable to complete checkout' });
    }
  };

  const handleTrackOrder = async () => {
    try {
      const response = await fetch('/api/v1/order-tracking/demo123');
      const data = await response.json();
      setTrackingResult(data);
    } catch (error) {
      console.error(error);
    }
  };

  const handleDashboard = async (role) => {
    setLastRole(role);
    try {
      const response = await fetch(`/api/v1/dashboard?role=${role}`);
      const data = await response.json();
      setDashboardData({ ...data, role });
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <div className="app-shell">
      <header className="hero">
        <div>
          <p className="eyebrow">Citywide delivery</p>
          <h1>Fresh food, curated menus, delivered to your door.</h1>
          <p className="lead">
            Choose from restaurants around town, follow your order in real time, and manage everything with role-aware dashboards.
          </p>
          <div className="hero-actions">
            <button onClick={handleCheckout} className="primary">
              Try demo checkout
            </button>
            <button onClick={handleTrackOrder} className="ghost">
              Track sample order
            </button>
          </div>
        </div>
        {featuredDish && (
          <div className="hero-card">
            <p className="tag">Chef special</p>
            <h3>{featuredDish.name}</h3>
            <p>{featuredDish.description}</p>
            <span>${featuredDish.price.toFixed(2)}</span>
          </div>
        )}
      </header>

      <section className="section">
        <div className="section-header">
          <div>
            <p className="eyebrow">Menu explorer</p>
            <h2>Browse today's featured plates</h2>
          </div>
          <span>Responsive grid • curated for every mood</span>
        </div>
        {loadingMenu ? (
          <p>Loading menu…</p>
        ) : (
          <div className="menu-grid">
            {menu.map((dish) => (
              <article key={dish.id} className="menu-card">
                <div className="menu-card__header">
                  <h3>{dish.name}</h3>
                  <span>${dish.price.toFixed(2)}</span>
                </div>
                <p>{dish.description}</p>
                <div className="menu-card__meta">
                  <p>{dish.category}</p>
                  <button className="base">Add</button>
                </div>
              </article>
            ))}
          </div>
        )}
      </section>

      <section className="section split">
        <div>
          <p className="eyebrow">Checkout & payments</p>
          <h2>Secure, transparent checkout</h2>
          <p>
            Sample order totals include delivery, tax, and a simulated payment token so UI teams can wire up real gateways later.
          </p>
          {checkoutResult && checkoutResult.success ? (
            <div className="result-card">
              <p className="tag">Order {checkoutResult.order.order_id}</p>
              <p>Total&nbsp;${checkoutResult.order.summary.total.toFixed(2)}</p>
              <p>Payment status: {checkoutResult.order.payment.status}</p>
            </div>
          ) : checkoutResult && checkoutResult.error ? (
            <div className="result-card error">{checkoutResult.error}</div>
          ) : (
            <div className="result-card ghost">Click “Try demo checkout” to simulate.</div>
          )}
        </div>
        <div className="order-tracking">
          <p className="eyebrow">Order tracking</p>
          <h3>Sample stage</h3>
          {trackingResult ? (
            <div>
              <p className="tag">{trackingResult.current_phase}</p>
              <p>ETA: {trackingResult.eta_minutes} min</p>
              <ul>
                {trackingResult.timeline.map((step) => (
                  <li key={step.stage} className={step.completed ? 'done' : ''}>
                    {step.stage}
                  </li>
                ))}
              </ul>
            </div>
          ) : (
            <div className="result-card ghost">Press “Track sample order” to see live data.</div>
          )}
        </div>
      </section>

      <section className="section">
        <div className="section-header">
          <div>
            <p className="eyebrow">Role-aware dashboards</p>
            <h2>Every persona stays informed</h2>
          </div>
          <div className="role-tabs">
            {['customer', 'restaurant', 'admin'].map((role) => (
              <button
                key={role}
                onClick={() => handleDashboard(role)}
                className={lastRole === role ? 'primary' : 'ghost'}
              >
                {role}
              </button>
            ))}
          </div>
        </div>
        {dashboardData ? (
          <div className="dashboard-card">
            <h3>{dashboardData.title}</h3>
            <dl>
              {Object.entries(dashboardData)
                .filter(([key]) => !['role', 'title'].includes(key))
                .map(([key, value]) => (
                  <div key={key}>
                    <dt>{key.replace(/_/g, ' ')}</dt>
                    <dd>{Array.isArray(value) ? JSON.stringify(value) : value}</dd>
                  </div>
                ))}
            </dl>
          </div>
        ) : (
          <p>Tap a role above to preview the dashboard.</p>
        )}
      </section>
    </div>
  );
}

export default App;

